#include <stdio.h>

float calculate_cpu_utilization(int cpu_busy_time, int total_time) {
    /*
     * Calculate CPU utilization as percentage
     * CPU Utilization = (Busy Time / Total Time) * 100
     */
    if (total_time == 0) {
        return 0.0;
    }
    return ((float)cpu_busy_time / total_time) * 100;
}

int main() {
    int total_time = 1000;    // Total observation time in ms
    int cpu_busy_time = 750;  // CPU was busy for 750ms

    float utilization = calculate_cpu_utilization(cpu_busy_time, total_time);

    printf("CPU Utilization: %.2f%%\n", utilization);
    printf("CPU Idle Time: %.2f%%\n", 100.0 - utilization);

    return 0;
}
